from collections import defaultdict

class Solution(object):
    def basicCalculatorIV(self, expression, evalvars, evalints):
        """
        :type expression: str
        :type evalvars: List[str]
        :type evalints: List[int]
        :rtype: List[str]
        """
        evalmap = {var: val for var, val in zip(evalvars, evalints)}

        def parse(expr):
            expr = expr.replace('(', '( ').replace(')', ' )')
            tokens = expr.split()

            def parse_expr(index):
                left, index = parse_term(index)
                while index < len(tokens) and tokens[index] in ['+', '-']:
                    op = tokens[index]
                    index += 1
                    right, index = parse_term(index)
                    if op == '+':
                        left = add(left, right)
                    else:
                        left = subtract(left, right)
                return left, index

            def parse_term(index):
                left, index = parse_factor(index)
                while index < len(tokens) and tokens[index] == '*':
                    index += 1
                    right, index = parse_factor(index)
                    left = multiply(left, right)
                return left, index

            def parse_factor(index):
                if tokens[index] == '(':
                    index += 1
                    result, index = parse_expr(index)
                    index += 1  # skip ')'
                    return result, index
                elif tokens[index].isdigit():
                    return Poly({(): int(tokens[index])}), index + 1
                else:
                    var = tokens[index]
                    if var in evalmap:
                        return Poly({(): evalmap[var]}), index + 1
                    return Poly({(var,): 1}), index + 1

            result, _ = parse_expr(0)
            return result

        def add(p1, p2):
            result = Poly(p1.poly.copy())
            for key, val in p2.poly.items():
                result.poly[key] = result.poly.get(key, 0) + val
            return result

        def subtract(p1, p2):
            result = Poly(p1.poly.copy())
            for key, val in p2.poly.items():
                result.poly[key] = result.poly.get(key, 0) - val
            return result

        def multiply(p1, p2):
            result = Poly({})
            for k1, v1 in p1.poly.items():
                for k2, v2 in p2.poly.items():
                    key = tuple(sorted(list(k1) + list(k2)))
                    result.poly[key] = result.poly.get(key, 0) + v1 * v2
            return result

        class Poly:
            def __init__(self, poly):
                self.poly = {k: v for k, v in poly.items() if v != 0}

        poly = parse(expression)

        # Format output
        result = []
        for key in sorted(poly.poly.keys(), key=lambda x: (-len(x), x)):
            if poly.poly[key] != 0:
                term = str(poly.poly[key])
                for var in key:
                    term += '*' + var
                result.append(term)

        return result if result else []
